                    if ($parent_id) {
                        $args = array(
                            'post_parent' => $parent_id,
                            'post_type'   => 'page',
                            'numberposts' => -1,
                            'post_status' => 'publish',
                            'post__not_in' => array($page_id),
                            'orderby'     => 'menu_order',
                            'order' => 'ASC',
                            'suppress_filters' => false,
                        );
                        $children = get_children($args);
                    } else {
                        $args = array(
                            'post_parent' => $page_id,
                            'post_type'   => 'page',
                            'numberposts' => -1,
                            'post_status' => 'publish',
                            'orderby'     => 'menu_order',
                            'order' => 'ASC',
                            'suppress_filters' => false,
                        );
